 public boolSpoofchecker::isSuspicious
 stringstring
 interrorCode&null;



 Метод проверяет, содержит ли текст подозрительные символы наподобие
 визуально неразличимых букв, которые при этом относятся к другому набору символов Юникода.

  &reftitle.examples;



    Пример проверки текста на подозрительные символы методом Spoofchecker::isSuspicious


<?php

$checker = new Spoofchecker();

$checker->isSuspicious('google.com'); // false: строка содержит только символы ASCII

$checker->isSuspicious('Рaypal.com'); // true
// Первая буква — не латинская "P", а кириллическое «эр»
